CREATE TABLE IF NOT EXISTS `views` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `content_type` enum('post','page','service') NOT NULL,
  `content_id` int(10) unsigned NOT NULL,
  `viewer_ip` varchar(45) NOT NULL,
  `viewed_at` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_views_content_time` (`content_type`,`content_id`,`viewed_at`),
  KEY `idx_views_ip_content_time` (`viewer_ip`,`content_type`,`content_id`,`viewed_at`)
) ENGINE=InnoDB AUTO_INCREMENT=322 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

